import{_ as t,o as a,c as o,a0 as d}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"Git no NEXUS","description":"","frontmatter":{},"headers":[],"relativePath":"40_Operacoes/guides/git.md","filePath":"40_Operacoes/guides/git.md","lastUpdated":1782592277000}'),s={name:"40_Operacoes/guides/git.md"};function i(n,e,r,c,l,u){return a(),o("div",null,[...e[0]||(e[0]=[d(`<h1 id="git-no-nexus" tabindex="-1">Git no NEXUS <a class="header-anchor" href="#git-no-nexus" aria-label="Permalink to &quot;Git no NEXUS&quot;">​</a></h1><h2 id="prefira-mcp-a-comandos-brutos" tabindex="-1">Prefira MCP a Comandos Brutos <a class="header-anchor" href="#prefira-mcp-a-comandos-brutos" aria-label="Permalink to &quot;Prefira MCP a Comandos Brutos&quot;">​</a></h2><p>O NEXUS oferece ferramentas MCP que substituem comandos git para navegação. Use-as antes de recorrer a <code>grep</code>, <code>find</code>, <code>git log -p</code>, ou loops de leitura.</p><table tabindex="0"><thead><tr><th>Em vez de</th><th>Use NEXUS MCP</th></tr></thead><tbody><tr><td><code>git log -S &quot;termo&quot; --all</code></td><td><code>nexus_query(&quot;termo&quot;, triangulate=true)</code></td></tr><tr><td><code>grep -r &quot;padrão&quot; src/</code></td><td><code>nexus_query(&quot;descrição do padrão&quot;)</code> + <code>nexus_map(module=&quot;...&quot;)</code></td></tr><tr><td><code>git diff --name-only</code> + <code>cat</code> loop</td><td><code>nexus_admin(action=&#39;enrich&#39;)</code> + <code>nexus_query()</code></td></tr><tr><td><code>ls src/modules/</code></td><td><code>nexus_map(module=&quot;module-name&quot;)</code></td></tr><tr><td><code>git blame</code> manual</td><td><code>nexus_query()</code> + <code>nexus_reflections()</code></td></tr></tbody></table><h2 id="quando-usar-git-diretamente" tabindex="-1">Quando Usar Git Diretamente <a class="header-anchor" href="#quando-usar-git-diretamente" aria-label="Permalink to &quot;Quando Usar Git Diretamente&quot;">​</a></h2><p>Git ainda é necessário para operações de escrita:</p><table tabindex="0"><thead><tr><th>Operação</th><th>Comando</th></tr></thead><tbody><tr><td>Commitar</td><td><code>git add</code> + <code>git commit</code></td></tr><tr><td>Push/Pull</td><td><code>git push</code> / <code>git pull</code></td></tr><tr><td>Merge/Rebase</td><td><code>git merge</code> / <code>git rebase</code></td></tr><tr><td>Branch</td><td><code>git checkout -b feature/...</code></td></tr></tbody></table><h2 id="convencoes-de-branch" tabindex="-1">Convenções de Branch <a class="header-anchor" href="#convencoes-de-branch" aria-label="Permalink to &quot;Convenções de Branch&quot;">​</a></h2><ul><li><code>feature/&lt;nome-descritivo&gt;</code> — funcionalidades novas</li><li><code>fix/&lt;descrição&gt;</code> — correções pontuais</li><li><code>docs/&lt;assunto&gt;</code> — documentação</li><li><code>hive/&lt;feature-id&gt;/&lt;task-id&gt;-&lt;desc&gt;</code> — tasks do Hive (worktrees isoladas)</li></ul><h2 id="mensagens-de-commit" tabindex="-1">Mensagens de Commit <a class="header-anchor" href="#mensagens-de-commit" aria-label="Permalink to &quot;Mensagens de Commit&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tipo(escopo): verbo no imperativo — motivo</span></span>
<span class="line"><span></span></span>
<span class="line"><span>tipos: feat, fix, docs, chore, refactor, perf, test, merge</span></span>
<span class="line"><span>escopo: arquivo ou módulo principal afetado</span></span></code></pre></div><p>Exemplos:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat(metrics): v2 collector with TTFT/TPOT latency tracking</span></span>
<span class="line"><span>fix(enrich): correct TPOT calculation (e_ms / e_cnt)</span></span>
<span class="line"><span>chore: add REFLECTION_MODEL to .env.example</span></span></code></pre></div><h2 id="fluxo-de-merge-final" tabindex="-1">Fluxo de Merge Final <a class="header-anchor" href="#fluxo-de-merge-final" aria-label="Permalink to &quot;Fluxo de Merge Final&quot;">​</a></h2><ol><li>Branch feature → PR no GitHub</li><li>Code Review (quando disponível)</li><li>Aplicar correções ou fechar PRs obsoletos</li><li>Merge para <code>main</code> via <code>git merge --ff-only</code> ou <code>gh pr merge</code></li><li>Push: <code>git push origin main</code></li></ol>`,15)])])}const h=t(s,[["render",i]]);export{m as __pageData,h as default};
